// Petstore Extended — drive the generated byte-native TypeScript client.
//
// This spec is tagged, so each tag gets its own generated client class (ApiPetsClient,
// ApiPhotosClient, …). We drive the "pets" client here. There is no live server in the playground, so
// globalThis.fetch is stubbed with canned responses (see the mock transport in the run engine); the
// FetchApiTransport then works entirely offline.
import { FetchApiTransport } from "@endjin/corvus-json-client-runtime";
import { ApiPetsClient } from "./ApiPetsClient.js";
import type { Pet, PetList } from "./models/generated.js";

const transport = new FetchApiTransport({ baseUrl: "https://petstore.example.com/v2" });
const client = new ApiPetsClient(transport);

function describe(pet: Pet): string {
  const tags = pet.tags && pet.tags.length > 0 ? ` [${pet.tags.join(", ")}]` : "";
  return `[${pet.id}] ${pet.name} — ${pet.status}${tags}`;
}

// ── 1. List pets (GET /pets) ─────────────────────────────────────────────────
// listPets takes a limit + tag filters and a required x-request-id correlation header.
console.log("1. Listing pets (limit=10)...");
const listResponse = await client.listPets({ xRequestId: "trace-001", limit: 10, tags: ["good-boy"] });
listResponse.match({
  ok: (pets: PetList) => {
    console.log(`   Got ${pets.length} pets`);
    for (const pet of pets) {
      console.log(`   - ${describe(pet)}`);
    }
  },
  default: (error) => {
    console.error(`   Error ${error.code}: ${error.message}`);
  },
});

// x-total-count / x-next are typed response headers.
const total = listResponse.xTotalCountHeader;
if (total !== undefined) {
  console.log(`   Total matching: ${total}`);
}

// ── 2. Create a pet (POST /pets) ─────────────────────────────────────────────
// createPet takes the operation parameters first (a required session_token cookie), then the request body.
console.log("2. Creating a pet...");
const createResponse = await client.createPet(
  { sessionToken: "session-abc" },
  { name: "Rex", breed: "Labrador", status: "available", tags: ["good-boy"] });
createResponse.match({
  created: (createdPet: Pet) => {
    console.log(`   Created: ${describe(createdPet)}`);
  },
  unauthorized: (error) => {
    console.error(`   Unauthorized ${error.code}: ${error.message}`);
  },
  default: (error) => {
    console.error(`   Error ${error.code}: ${error.message}`);
  },
});

// ── 3. Show a specific pet (GET /pets/{petId}) ───────────────────────────────
console.log("3. Showing pet by id...");
const showResponse = await client.showPetById({ petId: "42" });
showResponse.match({
  ok: (foundPet: Pet) => {
    console.log(`   Found: ${describe(foundPet)}`);
  },
  notFound: (error) => {
    console.error(`   Not found ${error.code}: ${error.message}`);
  },
});

console.log("Done!");